module top_module(clk, rst, count);input clk, rst;
output reg [3:0] count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
    if(rst)
        count <= 4'b0000;
    else if(count == 4'b1111)
        count <= 4'b0000;
    else
        count <= count + 1;
end

endmodule
